  const nmcEmergencyScenarios = [
    { scenario: "A patient on an NHS ward suddenly becomes unresponsive. The nurse checks for breathing and finds no signs of life", action: "call 2222 (cardiac arrest call), commence CPR immediately (30:2 ratio at 100-120 compressions/min, depth 5-6 cm), attach defibrillator as soon as available, follow the Resuscitation Council UK ALS algorithm, and document the event", topic: "Cardiac Arrest Response", difficulty: 3, bodySystem: "Cardiovascular" },
    { scenario: "A patient develops anaphylaxis after receiving IV antibiotics — widespread urticaria, facial swelling, wheezing, and hypotension", action: "stop the infusion immediately, call for help (2222), administer IM adrenaline 0.5mg (1:1000) into the anterolateral thigh, lie the patient flat with legs elevated, high-flow oxygen via non-rebreathe mask, IV fluid bolus (500 mL-1L crystalloid), and prepare to repeat adrenaline at 5-minute intervals if needed", topic: "Anaphylaxis Management", difficulty: 3, bodySystem: "Immunology" },
    { scenario: "A patient on the ward develops acute chest pain, diaphoresis, and dyspnoea — suspected acute coronary syndrome", action: "sit the patient upright, assess using ABCDE, call for immediate medical review, administer aspirin 300mg (if not contraindicated), sublingual GTN, morphine for pain (with anti-emetic), obtain a 12-lead ECG within 10 minutes, and prepare for transfer to cardiac catheterisation lab if STEMI confirmed", topic: "ACS Management", difficulty: 3, bodySystem: "Cardiovascular" },
    { scenario: "A patient with known epilepsy develops a tonic-clonic seizure on the ward that has lasted more than 5 minutes", action: "this is status epilepticus — a medical emergency. Protect the patient from injury (clear area, do NOT restrain or put anything in the mouth), maintain airway, position in recovery position when safe, administer IV lorazepam 4mg (or buccal midazolam 10mg if no IV access), note seizure duration, and call for emergency medical assistance", topic: "Status Epilepticus", difficulty: 3, bodySystem: "Neurological" },
    { scenario: "A patient with a tracheostomy develops sudden respiratory distress with inability to pass a suction catheter", action: "follow the NTSP emergency algorithm: remove the inner cannula, attempt to pass a suction catheter, if still obstructed remove the tracheostomy tube entirely, cover the stoma and ventilate via the oral route, call for specialist airway support, and prepare emergency equipment (replacement tube, bougie)", topic: "Tracheostomy Emergency", difficulty: 4, bodySystem: "Respiratory" },
    { scenario: "A diabetic patient becomes acutely confused, tremulous, and diaphoretic — capillary blood glucose is 2.1 mmol/L", action: "this is severe hypoglycaemia. If the patient can swallow, give fast-acting glucose (15-20g — glucose tablets, GlucoGel). If unable to swallow, administer IV 10% glucose 200mL or IM glucagon 1mg. Recheck BGL after 10-15 minutes, follow with long-acting carbohydrate once BGL >4 mmol/L, and investigate the cause", topic: "Severe Hypoglycaemia", difficulty: 3, bodySystem: "Endocrine" },
    { scenario: "A patient develops a massive haematemesis (vomiting large volumes of fresh blood) on the ward", action: "call for emergency medical assistance, insert two large-bore IV cannulae (14G or 16G), commence rapid IV fluid resuscitation (crystalloid), send urgent bloods (FBC, coagulation, U&Es, crossmatch 4-6 units), position the patient on their side (aspiration prevention), monitor observations every 5 minutes, and prepare for emergency endoscopy", topic: "Upper GI Haemorrhage", difficulty: 4, bodySystem: "Gastrointestinal" },
    { scenario: "A patient develops acute severe asthma — unable to complete sentences, respiratory rate 28, SpO2 89%, PEFR 33% of predicted", action: "sit the patient upright, administer high-flow oxygen (target SpO2 94-98%), nebulised salbutamol 5mg via oxygen-driven nebuliser, nebulised ipratropium 500mcg, oral prednisolone 40-50mg (or IV hydrocortisone 100mg if cannot swallow), and reassess. If life-threatening features (silent chest, cyanosis, bradycardia, exhaustion), call for ICU review", topic: "Acute Severe Asthma", difficulty: 3, bodySystem: "Respiratory" },
    { scenario: "A post-operative patient suddenly develops acute dyspnoea, pleuritic chest pain, and tachycardia — SpO2 88% — suspected pulmonary embolism", action: "administer high-flow oxygen, IV access, send urgent bloods (D-dimer, ABG, FBC, coagulation), ECG (look for right heart strain — S1Q3T3 pattern), and arrange urgent CTPA. If haemodynamically unstable (systolic BP <90), this is a massive PE — call for immediate senior medical/ICU review and consider thrombolysis", topic: "Pulmonary Embolism", difficulty: 4, bodySystem: "Respiratory" },
    { scenario: "A patient develops acute stroke symptoms — facial drooping, arm weakness, and speech difficulty (FAST positive)", action: "note the exact time of symptom onset (critical for thrombolysis window), call 2222/stroke team immediately, perform rapid ABCDE assessment, check blood glucose (hypoglycaemia can mimic stroke), do NOT give aspirin until haemorrhagic stroke is excluded by CT, keep nil by mouth until swallowing assessed, and facilitate urgent CT head scan", topic: "Acute Stroke", difficulty: 3, bodySystem: "Neurological" },
    { scenario: "A patient with a chest drain develops sudden respiratory distress and the underwater seal drain has been accidentally disconnected", action: "clamp the drain tubing close to the patient immediately (prevent pneumothorax worsening), reconnect the drainage system using a clean connection, unclamp once reconnected, observe for tidalling (confirms patency), assess respiratory status, obtain a chest X-ray, and complete an incident report", topic: "Chest Drain Emergency", difficulty: 3, bodySystem: "Respiratory" },
    { scenario: "A patient develops sepsis — temperature 38.9°C, heart rate 110, respiratory rate 24, lactate 3.2 mmol/L, blood pressure 88/52", action: "initiate the Sepsis Six bundle within 1 hour: 1) Take blood cultures, 2) Check serum lactate, 3) Give IV antibiotics (broad-spectrum per local guidelines), 4) Give IV fluid bolus (500mL crystalloid), 5) Administer high-flow oxygen (target SpO2 ≥94%), 6) Monitor hourly urine output. Escalate urgently if not responding to treatment", topic: "Sepsis Management", difficulty: 3, bodySystem: "Infections" },
  ];
