  const nmcChildNursing = [
    { scenario: "A 6-month-old infant is admitted with bronchiolitis and increasing respiratory distress", management: "assess using the paediatric assessment triangle (appearance, work of breathing, circulation), monitor SpO2 continuously (maintain ≥92%), humidified oxygen via nasal cannulae, ensure adequate hydration (small frequent feeds or NG if unable to feed), suction if nasal secretions are obstructing, minimal handling, and escalate if signs of exhaustion or apnoea", topic: "Bronchiolitis", difficulty: 3, bodySystem: "Respiratory" },
    { scenario: "A 3-year-old child presents to A&E with a non-blanching purpuric rash and fever", management: "this is meningococcal septicaemia until proven otherwise — a medical emergency. Administer IV/IM antibiotics immediately (ceftriaxone), obtain blood cultures if possible but do NOT delay antibiotics, fluid resuscitation if shocked, contact the paediatric retrieval team if in a DGH, isolate with droplet precautions, and notify public health", topic: "Meningococcal Septicaemia", difficulty: 4, bodySystem: "Infections" },
    { scenario: "A nurse suspects a child may be a victim of non-accidental injury — the child has multiple bruises of varying ages and the history is inconsistent", management: "follow safeguarding procedures: document findings objectively (using a body map), do NOT confront the parents/carers, refer to the named nurse for safeguarding children, contact the local safeguarding team, ensure the child is safe, and complete a safeguarding referral form. The welfare of the child is paramount (Children Act 1989)", topic: "Child Safeguarding", difficulty: 3, bodySystem: "Safety & Ethics" },
    { scenario: "A 4-year-old child weighing 20 kg requires IV paracetamol for post-operative pain", management: "calculate the dose based on weight: IV paracetamol for children over 10 kg = 15 mg/kg (max 60 mg/kg/day in divided doses, max single dose 1g). For a 20 kg child: 15 × 20 = 300 mg per dose, given 4-6 hourly. Always double-check paediatric drug calculations and use the paediatric BNF", topic: "Paediatric Drug Calculation", difficulty: 3, bodySystem: "Pharmacology" },
    { scenario: "A 2-year-old child is admitted with gastroenteritis, dehydration, and poor oral intake", management: "assess dehydration severity (mild: dry lips, reduced tears; moderate: reduced skin turgor, sunken eyes, tachycardia; severe: lethargy, absent tears, prolonged CRT), commence oral rehydration solution (ORS) if tolerated, IV fluids if moderate-severe dehydration or vomiting (0.9% NaCl + 5% glucose), strict fluid balance, and monitor weight daily", topic: "Paediatric Dehydration", difficulty: 3, bodySystem: "Gastrointestinal" },
    { scenario: "A 12-year-old child with type 1 diabetes presents with nausea, abdominal pain, deep rapid breathing (Kussmaul respirations), and a blood glucose of 28 mmol/L", management: "suspect diabetic ketoacidosis (DKA) — a medical emergency. Follow the BSPED DKA protocol: IV 0.9% NaCl fluid resuscitation, IV insulin infusion (0.05-0.1 units/kg/hr — do NOT bolus insulin), hourly BGL and fluid balance, 2-hourly electrolytes and blood gas, monitor for cerebral oedema (the most dangerous complication in paediatric DKA — headache, altered consciousness, bradycardia)", topic: "Paediatric DKA", difficulty: 4, bodySystem: "Endocrine" },
    { scenario: "A parent asks the nurse about the UK childhood vaccination schedule for their newborn", management: "the UK childhood vaccination schedule includes: 8 weeks (6-in-1, rotavirus, MenB), 12 weeks (6-in-1, PCV, rotavirus), 16 weeks (6-in-1, MenB), 1 year (Hib/MenC, MMR, PCV booster, MenB booster). The nurse should provide information, address vaccine concerns with evidence, and document vaccinations given. Contraindications include anaphylaxis to previous dose or components", topic: "Vaccination Schedule", difficulty: 2, bodySystem: "Immunology" },
    { scenario: "A nurse is conducting a developmental assessment on a 9-month-old infant", management: "at 9 months, expected milestones include: sits unsupported, transfers objects between hands, finger feeds, babbles with consonant sounds (dada/mama non-specifically), stranger anxiety, looks for dropped objects (object permanence). Use the ASQ-3 or similar validated screening tool. Refer for further assessment if concerns about developmental delay", topic: "Developmental Assessment", difficulty: 2, bodySystem: "Assessment Skills" },
    { scenario: "A child is prescribed oral antibiotics and the nurse needs to calculate the dose based on the child's weight", management: "always calculate paediatric doses by weight (mg/kg), verify against the paediatric BNF for maximum doses, use age-appropriate formulations (liquid for young children), measure liquid medications with an oral syringe (NOT a household spoon), and double-check calculations with a second nurse before administration", topic: "Paediatric Medication Safety", difficulty: 2, bodySystem: "Pharmacology" },
    { scenario: "A 7-year-old child with asthma presents to A&E with an acute exacerbation — unable to complete sentences, accessory muscle use, SpO2 91%", management: "this is acute severe asthma in a child. Administer oxygen via face mask (target SpO2 94-98%), salbutamol 10 puffs via spacer or 2.5-5mg nebulised (repeat every 20 minutes if needed), oral prednisolone 1-2mg/kg (max 40mg), add ipratropium bromide if poor response, and reassess. If life-threatening (SpO2 <92%, silent chest, cyanosis, exhaustion), escalate to PICU", topic: "Paediatric Asthma Emergency", difficulty: 3, bodySystem: "Respiratory" },
  ];
