  const nmcMaternityTopics = [
    { scenario: "A midwife/nurse is assessing a woman at 36 weeks gestation who reports reduced fetal movements", management: "take the concern seriously — do NOT use a kick chart or advise 'count to 10'. Perform immediate CTG monitoring (cardiotocography), assess fetal heart rate pattern, check maternal observations, and refer for consultant review. Reduced fetal movements are associated with stillbirth and must be investigated urgently per the Saving Babies' Lives Care Bundle", topic: "Reduced Fetal Movements", difficulty: 3, bodySystem: "Obstetrics" },
    { scenario: "A woman in labour develops a postpartum haemorrhage (PPH) — estimated blood loss >500 mL after vaginal delivery", management: "call for help immediately, rub up a contraction (uterine massage), administer IV oxytocin 10 IU, catheterise the bladder (full bladder prevents uterine contraction), commence IV fluid resuscitation, obtain blood for FBC, coagulation, and crossmatch, and if bleeding continues consider ergometrine, carboprost, or misoprostol. Major PPH (>1000 mL) is a life-threatening emergency", topic: "Postpartum Haemorrhage", difficulty: 4, bodySystem: "Obstetrics" },
    { scenario: "A postnatal woman on day 3 reports feeling tearful and overwhelmed — 'baby blues' vs postnatal depression", management: "baby blues are common (affect up to 80% of women), onset day 3-5, usually resolve within 10-14 days. Provide reassurance, support, and normalise the experience. If symptoms persist beyond 2 weeks, worsen, or include feelings of hopelessness, inability to bond, or suicidal ideation, screen for postnatal depression (Edinburgh Postnatal Depression Scale) and refer to perinatal mental health services", topic: "Postnatal Mental Health", difficulty: 3, bodySystem: "Mental Health" },
    { scenario: "A woman at 34 weeks gestation presents with a blood pressure of 162/108 mmHg, headache, visual disturbances, and epigastric pain", management: "this is pre-eclampsia with severe features — a medical emergency. Administer IV labetalol or nifedipine for blood pressure control, check for proteinuria, send urgent bloods (FBC, LFTs, renal function, clotting), assess for HELLP syndrome, consider IV magnesium sulphate for seizure prophylaxis (eclampsia prevention), continuous CTG, and plan for delivery", topic: "Severe Pre-eclampsia", difficulty: 4, bodySystem: "Obstetrics" },
    { scenario: "A nurse is supporting a breastfeeding mother whose newborn is not latching effectively", management: "assess positioning and attachment (baby's nose to nipple, wide gape, chin touching breast, more areola visible above upper lip), ensure skin-to-skin contact, observe a complete feed, check for tongue-tie (ankyloglossia), ensure the mother is comfortable and relaxed, and refer to an infant feeding specialist if problems persist. Avoid unnecessary formula supplementation", topic: "Breastfeeding Support", difficulty: 2, bodySystem: "Obstetrics" },
    { scenario: "A neonate born 2 hours ago has a temperature of 35.4°C", management: "neonatal hypothermia (normal range 36.5-37.5°C). Implement thermal care: skin-to-skin contact with the mother, dry the baby and place in a warm environment, use a hat, and recheck temperature in 30 minutes. If persistent hypothermia, check blood glucose (hypothermia can cause hypoglycaemia), and investigate for sepsis if other risk factors present", topic: "Neonatal Hypothermia", difficulty: 3, bodySystem: "Obstetrics" },
    { scenario: "A woman is admitted in established labour at 5 cm cervical dilatation with regular contractions", management: "provide one-to-one midwifery care, support the woman's birth plan preferences, assess progress using a partogram, offer pain relief options (Entonox, water, epidural), monitor fetal wellbeing (intermittent auscultation every 15 minutes in first stage, every 5 minutes in second stage, or continuous CTG if high-risk), and ensure adequate hydration", topic: "Intrapartum Care", difficulty: 2, bodySystem: "Obstetrics" },
    { scenario: "A newborn is assessed using the Apgar score at 1 and 5 minutes after birth", management: "assess 5 components, each scored 0-2: Appearance (colour), Pulse (heart rate), Grimace (reflex irritability), Activity (muscle tone), and Respiration. Score of 7-10 at 1 minute is normal. Score <7 requires intervention — stimulation, airway management, ventilation. If score remains low at 5 minutes, continue assessment at 10-minute intervals and escalate to neonatal team", topic: "Apgar Score Assessment", difficulty: 2, bodySystem: "Obstetrics" },
  ];
