  const ausCalculations = [
    { question: "A patient is prescribed an IV infusion of 1000 mL 0.9% sodium chloride over 6 hours using a volumetric pump. What rate should the pump be set at?", answer: "Rate = 1000 ÷ 6 = 166.67 mL/hr, rounded to 167 mL/hr", topic: "IV Infusion Rate" },
    { question: "A patient is prescribed morphine 8 mg IV. The available ampoule contains 15 mg/mL. What volume should be drawn up?", answer: "Volume = 8 ÷ 15 = 0.53 mL (round to 0.5 mL in practice — discuss with pharmacist if rounding is appropriate or if a dilution method should be used)", topic: "Opioid Dose Calculation" },
    { question: "A child weighing 22 kg is prescribed IV ceftriaxone at 50 mg/kg once daily. The reconstituted solution contains 250 mg/mL. What volume is required?", answer: "Dose = 50 × 22 = 1100 mg. Volume = 1100 ÷ 250 = 4.4 mL", topic: "Paediatric IV Antibiotic Calculation" },
    { question: "A patient is prescribed a heparin infusion at 1200 units/hour. The bag contains 25,000 units in 250 mL 0.9% NaCl. What rate should the pump be set at?", answer: "Concentration = 25,000 ÷ 250 = 100 units/mL. Rate = 1200 ÷ 100 = 12 mL/hour", topic: "Heparin Infusion Rate" },
    { question: "A patient is prescribed insulin at 6 units per hour. The syringe contains 50 units of actrapid in 50 mL 0.9% NaCl. What rate should the syringe pump be set at?", answer: "Concentration = 50 units/50 mL = 1 unit/mL. Rate = 6 units/hr ÷ 1 unit/mL = 6 mL/hour", topic: "Insulin Infusion Calculation" },
    { question: "A patient is prescribed enoxaparin 1 mg/kg subcutaneously for DVT treatment. The patient weighs 75 kg. Available pre-filled syringes are 60 mg/0.6 mL and 80 mg/0.8 mL. What dose and syringes should be used?", answer: "Dose = 1 × 75 = 75 mg. Use one 60 mg syringe + one 80 mg syringe, but only administer 0.15 mL from the 80 mg syringe (= 15 mg). In practice, verify with pharmacy — a 80 mg pre-filled syringe may be prescribed if appropriate", topic: "Weight-Based Anticoagulant Calculation" },
    { question: "Convert a dopamine infusion rate: the patient weighs 80 kg and is prescribed 5 mcg/kg/min. The bag contains 800 mg in 500 mL D5W. What is the pump rate?", answer: "Dose per minute = 5 × 80 = 400 mcg/min. Dose per hour = 400 × 60 = 24,000 mcg/hr = 24 mg/hr. Concentration = 800/500 = 1.6 mg/mL. Rate = 24/1.6 = 15 mL/hour", topic: "Inotrope Infusion Calculation" },
    { question: "A patient needs 250 mL of packed red blood cells transfused over 3 hours using a blood giving set (15 drops/mL). What is the drip rate?", answer: "Rate = (250 × 15) ÷ (3 × 60) = 3750 ÷ 180 = 20.8, rounded to 21 drops per minute", topic: "Blood Transfusion Rate" },
    { question: "A patient is prescribed oral digoxin 250 mcg daily. Available tablets are 62.5 mcg. How many tablets should be administered?", answer: "Number of tablets = 250 ÷ 62.5 = 4 tablets", topic: "Oral Dose Calculation" },
    { question: "A child weighing 15 kg is prescribed IV fluids using the Holliday-Segar formula for maintenance. What is the hourly rate?", answer: "First 10 kg: 100 mL/kg/day = 1000 mL/day. Next 5 kg: 50 mL/kg/day = 250 mL/day. Total = 1250 mL/day. Hourly rate = 1250 ÷ 24 = 52 mL/hour", topic: "Paediatric Maintenance Fluids" },
  ];
