  const ausInfectionControlExpanded = [
    { topic: "Standard precautions in Australian healthcare", correct: "apply to ALL patients: hand hygiene (5 Moments for Hand Hygiene — WHO framework adopted by Australia), PPE selection based on risk assessment, safe handling and disposal of sharps, routine environmental cleaning, safe handling of linen and waste, respiratory hygiene and cough etiquette, and aseptic technique for invasive procedures", wrong1: "Standard precautions only apply to patients with known infections", wrong2: "Hand hygiene is only needed before procedures", wrong3: "Gloves replace the need for hand decontamination" },
    { topic: "Contact precautions for multi-resistant organisms (MROs)", correct: "MROs (MRSA, VRE, ESBL, CRE) require contact precautions in addition to standard precautions: single room or cohort with same organism, dedicated equipment, gloves and gown for all contact, enhanced environmental cleaning, antimicrobial stewardship review, and screening of contacts per local policy", wrong1: "MROs do not require any additional precautions", wrong2: "Only MRSA requires contact precautions", wrong3: "MROs are airborne and require N95 respirators" },
    { topic: "Airborne precautions for tuberculosis (TB)", correct: "pulmonary TB requires airborne precautions: negative pressure isolation room, P2/N95 respirator for all staff entering the room, patient wears a surgical mask when leaving the room, notify public health for contact tracing, minimum 2 weeks of effective treatment before considering de-isolation, and sputum AFB clearance confirmation", wrong1: "TB only requires droplet precautions", wrong2: "Standard surgical masks are sufficient for TB", wrong3: "TB patients can share rooms with other patients" },
    { topic: "Hand hygiene — WHO 5 Moments", correct: "the 5 Moments for Hand Hygiene: 1. Before touching a patient, 2. Before a procedure, 3. After a procedure or body fluid exposure risk, 4. After touching a patient, 5. After touching patient surroundings. Use alcohol-based hand rub (ABHR) unless hands are visibly soiled, in which case use soap and water. ABHR is NOT effective against C. difficile spores", wrong1: "Hand hygiene is only needed before and after patient contact", wrong2: "Alcohol-based hand rub is effective against all organisms", wrong3: "Gloves replace the need for hand hygiene" },
    { topic: "Healthcare-associated infection (HAI) prevention bundles", correct: "evidence-based bundles reduce HAIs: CVC insertion and maintenance bundle (CLABSI prevention), ventilator bundle (VAP prevention), urinary catheter bundle (CAUTI prevention), and surgical site infection bundle. Each bundle has specific elements that must ALL be followed consistently. Compliance is monitored through clinical audits", wrong1: "HAI prevention bundles are optional best practice", wrong2: "Bundles only apply in ICU settings", wrong3: "Nurses are not responsible for bundle compliance" },
    { topic: "Influenza outbreak management in a healthcare facility", correct: "isolate symptomatic patients (droplet precautions), cohort nursing, surgical masks for staff providing direct care, enhanced hand hygiene, restrict symptomatic staff from work until 24 hours symptom-free, offer oseltamivir prophylaxis to exposed patients as per guidelines, notify infection control and public health, and restrict visitors", wrong1: "Influenza does not require specific infection control measures", wrong2: "N95 respirators are required for all influenza contacts", wrong3: "Symptomatic staff can work if wearing a mask" },
    { topic: "Needlestick and sharps injury management", correct: "wash the wound with soap and running water (do NOT squeeze), apply a dressing, report immediately to the nurse in charge, attend occupational health or emergency department, complete an incident report, identify the source patient (with consent for BBV testing), baseline bloods for the injured person (HIV, Hep B, Hep C), and assess need for post-exposure prophylaxis (PEP for HIV within 72 hours)", wrong1: "Squeeze the wound to remove contaminated blood", wrong2: "Apply alcohol to the wound site", wrong3: "Wait until the end of the shift to report" },
    { topic: "COVID-19 infection prevention and control in Australian healthcare", correct: "follow current IPC guidance (evolves with evidence): appropriate PPE based on risk assessment (standard, droplet, or airborne precautions depending on AGP status), screening and testing protocols, patient cohorting, environmental cleaning with TGA-approved disinfectants, ventilation optimization, and staff monitoring per current public health directives", wrong1: "Standard precautions are sufficient for COVID-19", wrong2: "COVID-19 IPC measures are no longer relevant", wrong3: "Only N95 masks are required for all COVID-19 patients" },
  ];
