  const ausAdditionalClinical = [
    { stem: "A patient in an Australian hospital has a central venous access device (CVAD). The nurse notes redness, swelling, and tenderness at the insertion site. What should be done?", correct: "suspect CVAD-related infection: take paired blood cultures (peripheral and through the CVAD), apply a fresh sterile dressing, do NOT remove the line until discussed with the treating team, commence empiric antibiotics if prescribed, review the CVAD care bundle compliance, and document findings", topic: "CVAD Infection Assessment" },
    { stem: "A patient receiving a blood transfusion develops fever, rigors, and urticaria 20 minutes into the transfusion. What is the immediate nursing action?", correct: "stop the transfusion immediately (keep IV line open with normal saline), call for medical review, check patient identification against the blood product label, send the blood bag and a fresh blood sample to the blood bank for investigation, administer antihistamine and paracetamol as prescribed for mild reactions, and monitor for progression to anaphylaxis", topic: "Transfusion Reaction" },
    { stem: "A patient on warfarin has an INR result of 7.8 with no active bleeding. What is the appropriate management?", correct: "withhold warfarin, administer oral vitamin K (1-2 mg as per local protocol), recheck INR the next day, investigate cause of elevated INR (medication interactions, dietary changes, illness, alcohol), and follow local haematology guidelines. If major bleeding occurs, give IV vitamin K and prothrombin complex concentrate (Prothrombinex)", topic: "Elevated INR Management" },
    { stem: "A patient is prescribed total parenteral nutrition (TPN) via a CVAD. What are the key nursing responsibilities?", correct: "administer via a dedicated lumen, strict aseptic technique for all line connections, monitor BGL 4-6 hourly initially (hyperglycaemia common), daily weight and fluid balance, monitor electrolytes daily (refeeding syndrome risk if malnourished — phosphate, potassium, magnesium), check the TPN bag matches the prescription, and assess the insertion site daily", topic: "TPN Administration" },
    { stem: "A patient with COPD is admitted with an acute exacerbation. The SpO2 is 86% on room air. What oxygen therapy is appropriate?", correct: "target SpO2 88-92% (NOT 94-98%), start with low-flow oxygen via nasal prongs 1-2 L/min or Venturi mask 24-28%, obtain ABG within 30-60 minutes of starting oxygen, monitor for signs of hypercapnia (drowsiness, confusion, headache, flapping tremor), and titrate oxygen carefully", topic: "Oxygen Therapy in COPD" },
    { stem: "A nurse is caring for a patient with a newly formed ileostomy after bowel surgery. What patient education should be provided?", correct: "teach stoma bag emptying and changing technique, stoma assessment (healthy stoma is red/pink, moist), skin care around the stoma (ensure good seal to prevent excoriation), expected output (ileostomy output is liquid/semi-liquid, typically 500-800 mL/day), hydration and electrolyte awareness (increased risk of dehydration and sodium depletion), dietary advice, and referral to stomal therapy nurse", topic: "Ileostomy Care Education" },
    { stem: "A patient develops acute kidney injury (AKI) — creatinine has risen to 2.5 times baseline. What are the key nursing interventions?", correct: "strict fluid balance (target urine output >0.5 mL/kg/hr), cease nephrotoxic medications (NSAIDs, ACE inhibitors/ARBs, aminoglycosides), ensure adequate hydration, monitor potassium urgently (hyperkalaemia risk — ECG if K+ >6.0 mmol/L), daily U&Es, and escalate if oliguria/anuria develops or potassium remains elevated", topic: "AKI Nursing Management" },
    { stem: "A patient is being discharged home on a new medication regimen. What medication counselling should the nurse provide?", correct: "use teach-back method to confirm understanding, explain each medication's purpose, dose, frequency, and route, discuss common side effects and when to seek medical attention, drug-food interactions, importance of adherence, safe storage, what to do if a dose is missed, and ensure the patient has follow-up arrangements for monitoring", topic: "Medication Discharge Education" },
    { stem: "A patient in an Australian hospital develops hospital-acquired pneumonia (HAP) on day 4 of admission — new fever, purulent sputum, and new infiltrate on chest X-ray", correct: "obtain sputum specimen for MC&S before commencing antibiotics, commence empiric antibiotics per local antibiogram (broader spectrum than CAP antibiotics), implement respiratory care bundle (oral hygiene, head of bed elevation ≥30 degrees, mobilisation), monitor respiratory status, and implement contact precautions if MRO is suspected", topic: "Hospital-Acquired Pneumonia" },
    { stem: "A patient with liver cirrhosis develops ascites and requires a paracentesis. What are the key nursing responsibilities?", correct: "ensure informed consent, assist with positioning (sitting upright or lateral), monitor observations during and after the procedure, measure and record the volume of fluid drained (large volume paracentesis >5L requires concurrent IV albumin 6-8g per litre drained), send fluid for MC&S, albumin, cell count, and monitor for complications (hypotension, peritonitis)", topic: "Paracentesis Nursing Care" },
    { stem: "A nurse is managing a patient receiving chemotherapy who develops febrile neutropenia — temperature 38.5°C and neutrophil count 0.3 × 10⁹/L", correct: "medical emergency: administer broad-spectrum IV antibiotics within 60 minutes of recognition, take blood cultures (peripheral ± CVAD), implement neutropenic precautions (protective isolation, no fresh flowers/fruit, hand hygiene enforcement), monitor observations frequently, and notify the oncology/haematology team", topic: "Febrile Neutropenia" },
    { stem: "A patient with chronic heart failure is being discharged from hospital. What are the key elements of discharge education?", correct: "daily weight monitoring (report gain of >2 kg in 2 days), fluid restriction if advised (typically 1.5L/day), sodium-restricted diet, medication adherence (explain purpose of each medication — ACE inhibitor, beta-blocker, diuretic), exercise within tolerance, recognise warning signs of decompensation (increasing dyspnoea, ankle swelling, weight gain), and follow-up with GP and heart failure nurse", topic: "Heart Failure Discharge Education" },
  ];
