    q.push({ stem: `A nurse in an Australian hospital reviews a patient's blood results showing elevated ${lab.lab} (normal range: ${lab.normal}). What does this indicate?`, options: [`Elevated: ${lab.high}`, `Low: ${lab.low}`, "Abnormal results should be ignored unless the patient is symptomatic", "Lab interpretation is only the doctor's responsibility"], correctAnswer: 0, rationale: `${lab.lab}: Normal ${lab.normal}. High: ${lab.high}. Nurses must recognise abnormal results and take appropriate action.`, domain: "Provision & Coordination of Care", bodySystem: lab.bodySystem, topic: `Lab — ${lab.lab}`, difficulty: 3, cognitiveLevel: "analysis", questionType: "MCQ_SINGLE", isMockExamEligible: false });
    q.push({ stem: `A nurse in an Australian hospital reviews a patient's blood results showing low ${lab.lab} (normal: ${lab.normal}). What is the clinical significance?`, options: [`Low: ${lab.low}`, `High: ${lab.high}`, "Low results are always insignificant", "Only the pathologist can interpret results"], correctAnswer: 0, rationale: `${lab.lab}: Normal ${lab.normal}. Low: ${lab.low}. Understanding lab interpretation is core nursing knowledge.`, domain: "Provision & Coordination of Care", bodySystem: lab.bodySystem, topic: `Lab — ${lab.lab}`, difficulty: 3, cognitiveLevel: "analysis", questionType: "MCQ_SINGLE", isMockExamEligible: false });
