    q.push({ stem: `A patient in an Australian hospital is prescribed both ${di.drug1} and ${di.drug2}. What drug interaction should the nurse be aware of?`, options: [di.interaction, "These medications have no known interactions", "Drug interactions are only the pharmacist's concern", "Administer both as prescribed without question"], correctAnswer: 0, rationale: `${di.drug1} + ${di.drug2}: ${di.interaction}. Medication safety is a core nursing competency.`, domain: "Provision & Coordination of Care", bodySystem: "Pharmacology", topic: di.topic, difficulty: 3, cognitiveLevel: "analysis", questionType: "MCQ_SINGLE", isMockExamEligible: false });
